   106→template <typename KEY_TYPE, typename POOL_TYPE>
   107→void ConnPoolMap<KEY_TYPE, POOL_TYPE>::drainConnections(
   108→    Envoy::ConnectionPool::DrainBehavior drain_behavior) {
   109→  // Copy the `active_pools_` so that it is safe for the call to result
   110→  // in deletion, and avoid iteration through a mutating container.
   111→  std::vector<POOL_TYPE*> pools;
   112→  pools.reserve(active_pools_.size());
   113→  for (auto& pool_pair : active_pools_) {
   114→    pools.push_back(pool_pair.second.get());
   115→  }
   116→
   117→  for (auto* pool : pools) {
   118→    pool->drainConnections(drain_behavior);
   119→  }
   120→}
   121→
   122→template <typename KEY_TYPE, typename POOL_TYPE>
   123→bool ConnPoolMap<KEY_TYPE, POOL_TYPE>::freeOnePool() {
   124→  // Try to find a pool that isn't doing anything.
   125→  auto pool_iter = active_pools_.begin();
   126→  while (pool_iter != active_pools_.end()) {
   127→    if (!pool_iter->second->hasActiveConnections()) {
   128→      break;
   129→    }
   130→    ++pool_iter;
   131→  }
   132→
   133→  if (pool_iter != active_pools_.end()) {
   134→    // We found one. Free it up, and let the caller know.
   135→    active_pools_.erase(pool_iter);
   136→    host_->cluster().resourceManager(priority_).connectionPools().dec();
   137→    return true;
   138→  }
   139→
   140→  return false;
   141→}
   142→
   143→template <typename KEY_TYPE, typename POOL_TYPE>
   144→void ConnPoolMap<KEY_TYPE, POOL_TYPE>::clearActivePools() {
   145→  host_->cluster().resourceManager(priority_).connectionPools().decBy(active_pools_.size());
   146→  active_pools_.clear();
   147→}
