    19→                                          concurrent_stream_limit),
    20→      parent_(parent), idle_timeout_(idle_timeout) {
    21→  Upstream::Host::CreateConnectionData data = host->createConnection(
    22→      parent_.dispatcher(), parent_.socketOptions(), parent_.transportSocketOptions());
    23→  real_host_description_ = data.host_description_;
    24→  connection_ = std::move(data.connection_);
    25→  connection_->addConnectionCallbacks(*this);
    26→  read_filter_handle_ = std::make_shared<ConnReadFilter>(*this);
    27→  connection_->addReadFilter(read_filter_handle_);
    28→  Upstream::ClusterTrafficStats& cluster_traffic_stats = *host->cluster().trafficStats();
    29→  connection_->setConnectionStats({cluster_traffic_stats.upstream_cx_rx_bytes_total_,
    30→                                   cluster_traffic_stats.upstream_cx_rx_bytes_buffered_,
    31→                                   cluster_traffic_stats.upstream_cx_tx_bytes_total_,
    32→                                   cluster_traffic_stats.upstream_cx_tx_bytes_buffered_,
    33→                                   &cluster_traffic_stats.bind_errors_, nullptr});
    34→  connection_->noDelay(true);
    35→  connection_->connect();
    36→
    37→  if (idle_timeout_.has_value()) {
    38→    idle_timer_ = connection_->dispatcher().createTimer([this]() -> void { onIdleTimeout(); });
