    72→void ActiveTcpClient::clearCallbacks() {
    73→  if (state() == Envoy::ConnectionPool::ActiveClient::State::Busy && parent_.hasPendingStreams()) {
    74→    auto* pool = &parent_;
    75→    pool->scheduleOnUpstreamReady();
    76→  }
    77→  callbacks_ = nullptr;
    78→  tcp_connection_data_ = nullptr;
