    84→void ActiveTcpClient::onEvent(Network::ConnectionEvent event) {
    85→  // If this is a newly established TCP connection, readDisable. This is to handle a race condition
    86→  // for TCP for protocols like MySQL where the upstream writes first, and the data needs to be
    87→  // preserved until a downstream connection is associated.
    88→  // This is also necessary for prefetch to be used with such protocols.
    89→  if (event == Network::ConnectionEvent::Connected) {
    90→    connection_->readDisable(true);
    91→  }
    92→  ENVOY_BUG(event != Network::ConnectionEvent::ConnectedZeroRtt,
    93→            "Unexpected 0-RTT event from the underlying TCP connection.");
    94→  parent_.onConnectionEvent(*this, connection_->transportFailureReason(), event);
    95→
    96→  if (event == Network::ConnectionEvent::LocalClose ||
    97→      event == Network::ConnectionEvent::RemoteClose) {
    98→    disableIdleTimer();
    99→
   100→    // Do not pass the Connected event to any session which registered during onEvent above.
   101→    // Consumers of connection pool connections assume they are receiving already connected
   102→    // connections.
   103→    if (callbacks_) {
   104→      if (tcp_connection_data_) {
   105→        Envoy::Upstream::reportUpstreamCxDestroyActiveRequest(parent_.host(), event);
   106→      }
   107→      callbacks_->onEvent(event);
   108→      // After receiving a disconnect event, the owner of callbacks_ will likely self-destruct.
   109→      // Clear the pointer to avoid using it again.
   110→      callbacks_ = nullptr;
   111→    }
   112→  }
   113→}
