   127→void ActiveTcpClient::setIdleTimer() {
   128→  if (idle_timer_ != nullptr) {
   129→    ASSERT(idle_timeout_.has_value());
   130→
   131→    idle_timer_->enableTimer(idle_timeout_.value());
   132→  }
   133→}
