   135→void ConnPoolImpl::drainConnections(Envoy::ConnectionPool::DrainBehavior drain_behavior) {
   136→  drainConnectionsImpl(drain_behavior);
   137→  if (drain_behavior == Envoy::ConnectionPool::DrainBehavior::DrainAndDelete) {
   138→    return;
   139→  }
   140→  // Legacy behavior for the TCP connection pool marks all connecting clients
   141→  // as draining.
   142→  for (auto& connecting_client : connecting_clients_) {
   143→    if (connecting_client->remaining_streams_ > 1) {
   144→      uint64_t old_limit = connecting_client->effectiveConcurrentStreamLimit();
   145→      connecting_client->remaining_streams_ = 1;
   146→      if (connecting_client->effectiveConcurrentStreamLimit() < old_limit) {
   147→        decrConnectingAndConnectedStreamCapacity(
   148→            old_limit - connecting_client->effectiveConcurrentStreamLimit(), *connecting_client);
   149→      }
   150→    }
   151→  }
   152→}
