   154→void ConnPoolImpl::closeConnections() {
   155→  for (auto* list : {&ready_clients_, &busy_clients_, &connecting_clients_}) {
   156→    while (!list->empty()) {
   157→      list->front()->close();
   158→    }
   159→  }
   160→}
