    22→class BasicResourceLimitImpl : public ResourceLimit {
    23→public:
    24→  BasicResourceLimitImpl(uint64_t max, Runtime::Loader& runtime, const std::string& runtime_key)
    25→      : max_(max), runtime_(&runtime), runtime_key_(runtime_key) {}
    26→  BasicResourceLimitImpl(uint64_t max) : max_(max) {}
