   136→// Updates the EDS health flags for an existing host to match the new host.
   137→// @param updated_host the new host to read health flag values from.
   138→// @param existing_host the host to update.
   139→// @return bool whether the flag update caused the host health to change.
   140→bool updateEdsHealthFlag(const Host& updated_host, Host& existing_host) {
   141→  auto updated_eds_health_status = updated_host.edsHealthStatus();
   142→
   143→  // Check if the health flag has changed.
   144→  if (updated_eds_health_status == existing_host.edsHealthStatus()) {
   145→    return false;
   146→  }
   147→
   148→  const auto previous_health = existing_host.coarseHealth();
   149→  existing_host.setEdsHealthStatus(updated_eds_health_status);
   150→
   151→  // Rebuild if changing the flag affected the host health.
   152→  return previous_health != existing_host.coarseHealth();
   153→}
