   155→// Converts a set of hosts into a HostVector, excluding certain hosts.
   156→// @param hosts hosts to convert
   157→// @param excluded_hosts hosts to exclude from the resulting vector.
   158→HostVector filterHosts(const absl::node_hash_set<HostSharedPtr>& hosts,
   159→                       const absl::node_hash_set<HostSharedPtr>& excluded_hosts) {
   160→  HostVector net_hosts;
   161→  net_hosts.reserve(hosts.size());
   162→
   163→  for (const auto& host : hosts) {
   164→    if (excluded_hosts.find(host) == excluded_hosts.end()) {
   165→      net_hosts.emplace_back(host);
   166→    }
   167→  }
   168→
   169→  return net_hosts;
   170→}
