   179→buildBaseSocketOptions(const envoy::config::cluster::v3::Cluster& cluster_config,
   180→                       const envoy::config::core::v3::BindConfig& bootstrap_bind_config) {
   181→  Network::ConnectionSocket::OptionsSharedPtr base_options =
   182→      std::make_shared<Network::ConnectionSocket::Options>();
   183→
   184→  // The process-wide `signal()` handling may fail to handle SIGPIPE if overridden
   185→  // in the process (i.e., on a mobile client). Some OSes support handling it at the socket layer:
   186→  if (ENVOY_SOCKET_SO_NOSIGPIPE.hasValue()) {
   187→    Network::Socket::appendOptions(base_options,
   188→                                   Network::SocketOptionFactory::buildSocketNoSigpipeOptions());
   189→  }
   190→  // Cluster IP_FREEBIND settings, when set, will override the cluster manager wide settings.
   191→  if ((bootstrap_bind_config.freebind().value() &&
   192→       !cluster_config.upstream_bind_config().has_freebind()) ||
   193→      cluster_config.upstream_bind_config().freebind().value()) {
   194→    Network::Socket::appendOptions(base_options,
   195→                                   Network::SocketOptionFactory::buildIpFreebindOptions());
   196→  }
   197→  if (cluster_config.upstream_connection_options().has_tcp_keepalive()) {
   198→    Network::Socket::appendOptions(base_options,
   199→                                   Network::SocketOptionFactory::buildTcpKeepaliveOptions(
   200→                                       parseTcpKeepaliveConfig(cluster_config)));
   201→  }
   202→
   203→  return base_options;
   204→}
